import{c as s,Q as t,j as d,m as a}from"./chunks/framework.D9IbVcwA.js";const g=JSON.parse('{"title":"002-boot-gdt-protected-3 · GDT 与保护模式","description":"","frontmatter":{"title":"002-boot-gdt-protected-3 · GDT 与保护模式"},"headers":[],"relativePath":"hands-on/002-boot-gdt-protected-3.md","filePath":"hands-on/002-boot-gdt-protected-3.md","lastUpdated":1779686691000}'),i={name:"hands-on/002-boot-gdt-protected-3.md"};function o(n,e,p,l,c,r){return t(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="_002-3-·-切换到保护模式" tabindex="-1">002-3 · 切换到保护模式 <a class="header-anchor" href="#_002-3-·-切换到保护模式" aria-label="Permalink to &quot;002-3 · 切换到保护模式&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>前两篇我们把 GDT 定义好了、linker script 修正了、debugcon 配置到位了——整个舞台已经搭好，只差最后也是最关键的一幕：让 CPU 真正从实模式切换到保护模式。这一步涉及一系列必须严格按序执行的操作：关中断、清 DS、加载 GDTR、设置 CR0 的 PE 位、执行远跳转，然后在 32 位环境下初始化段寄存器和栈。</p><p>整个过程容不得半点差错——任何一步的顺序或操作码出问题，等待你的都是经典的三重故障（Triple Fault），QEMU 窗口直接关闭，连报错的机会都不给你。</p><p>本篇我们就逐步拆解保护模式切换的每一步，搞清楚为什么每一步必须存在、为什么在这个位置、如果省略或调换会发生什么。所有代码改动集中在 <code>boot/stage2.S</code> 的 <code>_start</code> 函数末尾，从 VESA 初始化完成之后开始。</p><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-4-切换到保护模式" tabindex="-1">Step 4: 切换到保护模式 <a class="header-anchor" href="#step-4-切换到保护模式" aria-label="Permalink to &quot;Step 4: 切换到保护模式&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>stage2.S</code> 的 <code>_start</code> 函数中，VESA 初始化和内核加载完成后，依次执行：关中断 -&gt; DS 清零 -&gt; lgdt -&gt; CR0.PE 置 1 -&gt; 远跳转到 <code>.code32</code> 入口点。</p><p><strong>设计思路</strong>: 让我们一步步解释为什么每一步都不可少，以及它们之间的依赖关系。Intel SDM Volume 3A Section 10.9.1 给出了严格的切换步骤，顺序不可调换，任何一步缺失都可能导致不可预测的 CPU 行为。</p><p>首先是 <code>cli</code> 关中断。进入保护模式后，BIOS 的中断向量表（IVT）就失效了，而我们的 IDT 还没建立。如果这时候发生任何中断（包括定时器中断），CPU 会尝试查一个不存在的 IDT，直接触发 double fault，然后 triple fault，QEMU 重启。</p><p>所以在切换开始前必须把中断关掉。注意 <code>cli</code> 在 stage2 一开始就执行过一次（在 <code>_start</code> 入口处），后来 <code>sti</code> 重新开了中断给 VESA 的 BIOS 调用和内核加载用。现在所有实模式操作全部结束，是时候再次关掉了。</p><p>然后是把 DS 清零。这一点特别容易被忽略，但查起来让人血压拉满。在实模式下，所有内存访问的物理地址都是 <code>DS * 16 + offset</code>。当我们执行 <code>lgdt gdt_ptr</code> 时，CPU 读 <code>gdt_ptr</code> 的物理地址就是 <code>DS * 16 + gdt_ptr</code>。</p><p>如果 DS 不为 0（比如还是之前 VESA 调用后残留的某个值），CPU 就会从错误的位置读取 GDT 指针，加载一堆垃圾到 GDTR 里。这个问题特别难定位，因为 <code>lgdt</code> 本身不会报错——它只是默默地把数据搬进 GDTR，错误要等到后续第一次段访问时才会暴露。</p><p>我们在调试时确实踩到了这个坑，花了大半个小时才定位到是 DS 没清零导致 lgdt 读到了错误地址。</p><p>接下来是 <code>lgdt gdt_ptr</code>，这条指令从内存中读取 6 字节的 GDT 指针结构（2 字节 limit + 4 字节 base），加载到 GDTR 寄存器。Intel SDM Volume 3A Section 2.4.1 对此有详细说明。</p><p>注意 <code>lgdt</code> 本身不校验 GDT 内容的合法性，它只是做了一次内存拷贝。如果 GDT 里的描述符是乱写的，<code>lgdt</code> 不会报错，错误会在后续 <code>ljmp</code> 尝试加载 CS 时才暴露——CPU 查到无效描述符直接触发 #GP。</p><p>然后是设置 CR0 的 PE 位：把 CR0 读到 EAX，把最低位（bit 0）或上 1，再写回 CR0。这一步是&quot;通知&quot;CPU 进入保护模式，但此时 CPU 流水线里还缓存着按 16 位实模式取的指令，CS 寄存器还指向实模式的段。</p><p>所以 PE 位设完之后，必须马上做一个远跳转。注意这里不能直接对 CR0 做 <code>or</code> 操作，必须先读出来、修改、再写回去——这是因为 CR0 不能作为 ALU 指令的操作数，必须通过通用寄存器中转。这是 x86 ISA 的规定。</p><p>远跳转是整个流程中最关键的一步。远跳转的操作数同时指定了新的代码段选择子（<code>0x08</code>）和目标偏移地址（<code>pm_entry</code>），CPU 在执行这个跳转时会把 CS 刷新为新选择子指向的段描述符，同时清空流水线中的预取指令队列，从新的 CS:EIP 开始以 32 位模式重新取指令。</p><p>如果不做这个跳转，后续的 32 位指令会被当作 16 位来解码，几乎必定执行非法指令然后崩溃。</p><p>关于远跳转的编码，有一个好消息：在 <code>.code16</code> 模式下，GAS 会自动把远跳转指令编码为正确的 16 位远跳转格式（操作码 <code>EA</code> + 2 字节偏移 + 2 字节选择子）。因为 stage2 的代码全部在 <code>0x8000</code>-<code>0x10000</code> 范围内，16 位偏移足够表示。你不需要手动拼机器码，汇编器会帮你处理好。</p><p><strong>踩坑预警</strong>: 如果你在 lgdt 之前忘记把 DS 清零，表面上不会报任何错误，但后续远跳转时 CPU 会从错误的 GDT 条目里取段描述符，大概率触发 General Protection Fault 或者 triple fault。</p><p>另一个常见问题是有人在远跳转的目标地址上手动减去了加载偏移（比如写 <code>pm_entry - 0x8000</code>），这是不必要的——因为 linker script 已经把 base 设成了 <code>0x8000</code>，链接器算出来的 <code>pm_entry</code> 地址本身就是正确的物理地址，再减一次就跳到错误的内存去了。</p><p><strong>验证</strong>: 在远跳转指令处设 GDB 断点，确认 CR0 的 PE 位已经被置 1：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/boot/stage2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :1234</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">break</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pm_entry</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">continue</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cr0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>注意要用 ELF 文件（<code>build/boot/stage2</code>）而不是 bin 文件——ELF 包含符号表，GDB 才能正确识别函数名。CR0 的值应该是 <code>0x...1</code>（最低位为 1）。</p><hr><h3 id="step-5-保护模式段寄存器初始化与验证输出" tabindex="-1">Step 5: 保护模式段寄存器初始化与验证输出 <a class="header-anchor" href="#step-5-保护模式段寄存器初始化与验证输出" aria-label="Permalink to &quot;Step 5: 保护模式段寄存器初始化与验证输出&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>.code32</code> 的 <code>pm_entry</code> 入口点中，把 DS、ES、FS、GS、SS 全部加载为数据段选择子 <code>0x10</code>，设置栈指针到 <code>0x90000</code>，然后向端口 <code>0xE9</code> 输出字母 <code>P</code>。</p><p><strong>设计思路</strong>: 远跳转完成后，CS 已经被自动刷新为代码段选择子 <code>0x08</code>，但其他段寄存器（DS、ES、FS、GS、SS）还残留着实模式的值。</p><p>在保护模式下，这些段寄存器也要通过段选择子来寻址，如果不更新，任何内存访问都会因为使用无效的实模式段值而触发异常。所以进入保护模式的第一件事就是统一加载所有数据段寄存器为 <code>0x10</code>（数据段选择子，即 GDT 中索引 2 的数据段描述符）。</p><p>栈段的设置也不能遗漏。SS 必须指向有效的数据段描述符，栈指针我们设在 <code>0x90000</code>。</p><p>这个地址的选择有几个原因叠在一起：第一，它不会和 stage2 的代码区域（<code>0x8000</code>-<code>0x10000</code>）冲突；第二，它远离 VESA 缓冲区（<code>0x6000</code>-<code>0x64FF</code>）和 E820 内存映射（<code>0x5000</code>-<code>0x5FFF</code>）；第三，从 <code>0x90000</code> 向下增长到 <code>0x80000</code> 有整整 64KB 的空间，对 Bootloader 阶段来说绰绰有余。</p><p>在 Flat Memory Model 下，SS 对应的数据段 Base 是 <code>0x00000000</code>，所以 <code>0x90000</code> 就是实际的物理栈顶地址。在实模式阶段，我们用的是 <code>SS:SP = 0x9000:0xFFFE</code>，对应物理地址 <code>0x9000 * 16 + 0xFFFE = 0x9FFFE</code>。进入保护模式后，段寄存器的语义变了——SS 不再存储段地址，而是存储段选择子，所以我们重新把 SS 设成 <code>0x10</code>，然后直接设 ESP 为 <code>0x90000</code>。</p><p>最后是验证输出。进入保护模式后，BIOS 中断全部失效，我们不能再用 INT 10h 打印字符了。QEMU 提供了一个非常方便的调试接口叫 debugcon：向 I/O 端口 <code>0xE9</code> 写入一个字节，QEMU 就会把这个字节输出到 debugcon 设备。</p><p>我们向它写入 <code>0x50</code>（字母 <code>P</code> 的 ASCII 码），如果一切顺利，<code>debug.log</code> 里就会看到这个 <code>P</code>。这是保护模式下最简单的输出手段，不需要初始化 UART、不需要配置串口，一个简单的输出指令搞定。</p><p>验证输出完成后，stage2 的保护模式阶段在这个 tag 里就结束了。我们还没有实现后续的 long mode 切换（那是 tag 003 的事），所以代码进入停机循环：<code>cli</code> 加 <code>hlt</code> 加无条件跳转死循环，确保 CPU 不会跑飞。</p><p><strong>验证</strong>: 构建 Stage2 并打包到磁盘镜像，然后运行 QEMU：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等待几秒后 Ctrl+C 退出 QEMU</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug.log</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应该能看到字母 P</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果你在 <code>debug.log</code> 中看到了字母 <code>P</code>，恭喜你——实模式到保护模式的切换已经成功了。如果什么都没出现或者 QEMU 反复重启，按照下面的调试技巧逐一排查。</p><hr><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><h3 id="gdb-断点调试" tabindex="-1">GDB 断点调试 <a class="header-anchor" href="#gdb-断点调试" aria-label="Permalink to &quot;GDB 断点调试&quot;">​</a></h3><p>在保护模式切换这种底层代码里，GDB 是你最可靠的朋友。启动 QEMU 的调试模式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run-debug</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>然后在另一个终端连上 GDB：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/boot/stage2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :1234</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>注意这里要用 ELF 文件（<code>build/boot/stage2</code>）而不是 bin 文件（<code>build/boot/stage2.bin</code>）。ELF 文件包含符号表和调试信息，GDB 才能正确识别函数名和行号；bin 文件只是裸二进制，没有任何元数据，GDB 拿到它就像看一堆字节，断点和符号全都对不上。</p><p>在 GDB 中可以设置几个关键断点：在 <code>_start</code> 处确认 Stage2 入口正常，在远跳转指令处确认 lgdt 已经执行完毕，在 <code>pm_entry</code> 处确认保护模式入口被正确跳转到。到达 <code>pm_entry</code> 后，用 <code>info registers</code> 查看 CR0 的 PE 位是否为 1，段寄存器是否指向正确的选择子。</p><h3 id="qemu-中断日志" tabindex="-1">QEMU 中断日志 <a class="header-anchor" href="#qemu-中断日志" aria-label="Permalink to &quot;QEMU 中断日志&quot;">​</a></h3><p>如果 CPU 在某个时刻 triple fault 了（QEMU 窗口直接关闭或者重启），用 <code>-d int</code> 参数启动 QEMU 可以看到所有中断和异常的记录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-system-x86_64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -drive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> format=raw,file=build/cinux.img</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> int</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu_int.log</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -serial</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -debugcon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -no-reboot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后在 <code>qemu_int.log</code> 里搜索 <code>exception</code> 或 <code>fault</code> 关键字，看看是哪种异常、发生在什么地址。最常见的三种：General Protection Fault 通常是段选择子或描述符有问题，Page Fault 在这个阶段不太可能（还没开分页），Double/Triple Fault 说明前一个异常的处理又触发了异常。</p><h3 id="debugcon-面包屑调试" tabindex="-1">debugcon 面包屑调试 <a class="header-anchor" href="#debugcon-面包屑调试" aria-label="Permalink to &quot;debugcon 面包屑调试&quot;">​</a></h3><p>在整个 bootloader 开发过程中，debugcon（端口 <code>0xE9</code>）是最轻量的调试输出方式。它不需要初始化任何硬件，不需要配置波特率，只需要向端口 <code>0xE9</code> 写一个字节即可。</p><p>你可以在代码的任何可疑位置插入一个输出操作，输出不同的字符来标记执行到了哪里——比如在 lgdt 前后各输出一个字符，在 CR0 写入后输出一个字符，在远跳转后输出一个字符。通过观察哪些字符出现了、哪些没出现，就能快速定位崩溃发生在哪一步。这比 GDB 单步调试快得多，尤其是你只是想知道&quot;有没有执行到这里&quot;的时候。</p><hr><h2 id="常见-triple-fault-排查" tabindex="-1">常见 Triple Fault 排查 <a class="header-anchor" href="#常见-triple-fault-排查" aria-label="Permalink to &quot;常见 Triple Fault 排查&quot;">​</a></h2><p>这里总结几种最常见的 triple fault 原因和对应的排查方向，按出现频率排序。</p><p><strong>lgdt 读到了错误的 GDT 地址。</strong> 最常见的坑，原因是 <code>lgdt</code> 前 DS 没有清零。实模式下 <code>lgdt</code> 用 <code>DS * 16 + offset</code> 计算地址，DS 不为 0 就会读到错误位置。排查方法：在 <code>lgdt</code> 前后各加一个 debugcon 输出，如果前一个字符出现了后一个没有，大概率是 <code>lgdt</code> 导致的三重故障。</p><p><strong>GDT 描述符定义错误。</strong> Access Byte 写错一位、Limit 不够大、Base 地址错误，这些都会导致 <code>ljmp</code> 时 CPU 查到无效描述符触发 #GP。排查方法：用 <code>objdump -s -j .gdt build/boot/stage2</code> 检查编译后的 <code>.gdt</code> section，逐字节对照 Intel SDM Vol.3A Section 3.4.5 的描述符格式。</p><p><strong>linker script base 地址不匹配。</strong> stage2 被加载到 <code>0x8000</code>，但 linker script 的 location counter 设成了 <code>0x0</code>，导致所有绝对地址引用偏移 <code>0x8000</code>。排查方法：用 <code>readelf -s build/boot/stage2 | grep gdt</code> 查看 <code>gdt</code> 符号的链接地址，如果比预期小 <code>0x8000</code>，就是 base 没设对。</p><p><strong>省略了 far jump。</strong> CR0.PE 设完之后直接写 32 位代码，没有远跳转刷新 CS 的隐藏缓存。CPU 还在用 16 位模式解码，32 位编码的指令被解析成乱码。排查方法：检查 CR0 写入后是否紧跟远跳转指令，中间不能有任何其他指令。</p><hr><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>到这里，我们已经完成了 bootloader 开发中最关键的里程碑之一：把 CPU 从 16 位实模式成功推进到 32 位保护模式。</p><p>下面是本章涉及的关键概念和数值总结：</p><table tabindex="0"><thead><tr><th>概念</th><th>值/位置</th><th>说明</th></tr></thead><tbody><tr><td><code>.code16</code></td><td>serial.S, stage2.S</td><td>严格 16 位指令编码，替代 <code>.code16gcc</code></td></tr><tr><td><code>pushw</code>/<code>popw</code></td><td>serial.S</td><td>显式 16 位栈操作，防止宽度不一致</td></tr><tr><td>Linker base</td><td><code>0x8000</code></td><td>Stage2 的加载地址，linker script 必须匹配</td></tr><tr><td><code>.gdt</code> section</td><td>stage2.S</td><td>独立、8 字节对齐的 GDT 存储区</td></tr><tr><td>Null 描述符</td><td>索引 0, 8 字节全零</td><td>Intel 硬件强制要求</td></tr><tr><td>Code32 描述符</td><td>索引 1, 选择子 <code>0x08</code></td><td>Base=0, Limit=4GB, 可执行可读, Ring 0</td></tr><tr><td>Data32 描述符</td><td>索引 2, 选择子 <code>0x10</code></td><td>Base=0, Limit=4GB, 可读写, Ring 0</td></tr><tr><td>Access Byte (code)</td><td><code>0x9A</code></td><td>P=1, DPL=00, S=1, Type=1010(代码/可执行/可读)</td></tr><tr><td>Access Byte (data)</td><td><code>0x92</code></td><td>P=1, DPL=00, S=1, Type=0010(数据/可读写)</td></tr><tr><td>Flags (code/data)</td><td><code>0xCF</code></td><td>G=1(4KB), D=1(32位), Limit高4位=0xF</td></tr><tr><td><code>gdt_ptr</code></td><td>2 字节 limit + 4 字节 base</td><td><code>lgdt</code> 指令读取的 6 字节伪描述符</td></tr><tr><td>CR0.PE</td><td>bit 0 = 1</td><td>Protection Enable，开启保护模式</td></tr><tr><td>远跳转</td><td><code>ljmp $0x08, $pm_entry</code></td><td>刷新 CS 和流水线，真正进入 32 位</td></tr><tr><td>debugcon 端口</td><td><code>0xE9</code></td><td>QEMU 调试输出，向端口写入即可</td></tr><tr><td>栈指针</td><td><code>0x90000</code></td><td>保护模式下的 ESP 初始值</td></tr></tbody></table><p>下一篇（tag 003）我们将继续往上走——从 32 位保护模式进入 64 位长模式。长模式的切换需要设置页表、启用 PAE 和 EFER.LME，流程比保护模式切换更长也更复杂，但底层的思路是一样的：按顺序做、每步验证、不要跳步。</p>`,70)])])}const k=s(i,[["render",o]]);export{g as __pageData,k as default};
